let submission = AsyncDeliverySubmission {
    original_tx_hash: tx_hash,
    delivery_result: request.result,
    delivery_proof: request.proof,
    zk_proof: request.zk_proof,
};

pub zk_proof: Option<Bytes>,
...
metadata.delivery_result = Some(submission.delivery_result);
metadata.delivery_proof = Some(submission.delivery_proof);
metadata.zk_proof = submission.zk_proof;
metadata.state = AsyncState::DeliveryReady;

let callback_delivery_result = if contract_job.precompile_address == ZK_TWO_PHASE_PRECOMPILE {
    let zk_proof = metadata.zk_proof.clone().unwrap_or_else(|| Bytes::from(vec![0u8; 32]));
    Bytes::from((raw_delivery_result.clone(), zk_proof).abi_encode())
} else {
    raw_delivery_result.clone()
};
